import React, { useState, useEffect } from 'react';
import { useMutation, useQuery, gql } from '@apollo/client';
import { Card, CardHeader, CardContent, Typography } from '@material-ui/core';

const PRODUCT_FILTER_MUTATION = gql`
  mutation ProductFilter($category: String, $minPrice: Int, $maxPrice: Int, $minRating: Int, $maxRating: Int) {
    productFilter(category: $category, minPrice: $minPrice, maxPrice: $maxPrice, minRating: $minRating, maxRating: $maxRating) {
      products {
        id
        name
        price
        rating
      }
    }
  }
`;

const PRODUCT_FILTER_QUERY = gql`
  query ProductFilterQuery($category: String, $minPrice: Int, $maxPrice: Int, $minRating: Int, $maxRating: Int) {
    productFilter(category: $category, minPrice: $minPrice, maxPrice: $maxPrice, minRating: $minRating, maxRating: $maxRating) {
      products {
        id
        name
        price
        rating
      }
    }
  }
`;

const ProductFilter = () => {
  const [category, setCategory] = useState('');
  const [minPrice, setMinPrice] = useState(0);
  const [maxPrice, setMaxPrice] = useState(0);
  const [minRating, setMinRating] = useState(0);
  const [maxRating, setMaxRating] = useState(0);
  const [productFilter, { loading, error }] = useMutation(PRODUCT_FILTER_MUTATION);
  const { data, error: queryError, loading: queryLoading } = useQuery(PRODUCT_FILTER_QUERY, {
    variables: { category, minPrice, maxPrice, minRating, maxRating },
  });

  useEffect(() => {
    if (error) {
      console.error(error);
    }
    if (queryError) {
      console.error(queryError);
    }
  }, [error, queryError]);

  const handleFilter = () => {
    productFilter({ variables: { category, minPrice, maxPrice, minRating, maxRating } });
  };

  if (queryLoading) {
    return <div>Loading...</div>;
  }

  if (error) {
    return <div>Error: {error.message}</div>;
  }

  if (data.productFilter.products.length === 0) {
    return <div>No products found.</div>;
  }

  return (
    <div>
      <Card>
        <CardHeader title="Product Filter" />
        <CardContent>
          <Typography variant="body1">Category:</Typography>
          <select value={category} onChange={(e) => setCategory(e.target.value)}>
            <option value="">All</option>
            <option value="electronics">Electronics</option>
            <option value="clothing">Clothing</option>
            <option value="home goods">Home Goods</option>
          </select>
          <br />
          <Typography variant="body1">Price Range:</Typography>
          <input
            type="number"
            value={minPrice}
            onChange={(e) => setMinPrice(e.target.valueAsNumber)}
          />
          <input
            type="number"
            value={maxPrice}
            onChange={(e) => setMaxPrice(e.target.valueAsNumber)}
          />
          <br />
          <Typography variant="body1">Rating:</Typography>
          <input
            type="number"
            value={minRating}
            onChange={(e) => setMinRating(e.target.valueAsNumber)}
          />
          <input
            type="number"
            value={maxRating}
            onChange={(e) => setMaxRating(e.target.valueAsNumber)}
          />
          <br />
          <button onClick={handleFilter}>Filter</button>
        </CardContent>
      </Card>
      <Card>
        <CardContent>
          {data.productFilter.products.map((product) => (
            <Card key={product.id} style={{ margin: 10 }}>
              <Typography variant="h5">{product.name}</Typography>
              <Typography variant="body2">Price: ${product.price}</Typography>
              <Typography variant="body2">Rating: {product.rating}/5</Typography>
            </Card>
          ))}
        </CardContent>
      </Card>
    </div>
  );
};

export default ProductFilter;
