from datetime import datetime

def add_task(tasks, task):
    if 'task_name' not in task or 'priority' not in task:
        raise ValueError("Task must have 'task_name' and 'priority' fields")

    if task['priority'] not in ['High', 'Medium', 'Low']:
        raise ValueError("Priority must be 'High', 'Medium', or 'Low'")

    if 'due_date' in task and not isinstance(task['due_date'], str):
        raise ValueError("Due date must be a string")

    tasks.append(task)

def list_tasks_by_priority(tasks):
    def priority_sort(task):
        priorities = {'High': 2, 'Medium': 1, 'Low': 0}
        return priorities[task['priority']], task

    return sorted(tasks, key=priority_sort)

