from django.core.validators import MaxValueValidator

from .models import Patient
from .serializers import PatientSerializer
from oauth2_provider.contrib.rest_framework import OAuth2PermissionClass

class PatientUpdateView(RetrieveUpdateAPIView):
    permission_classes = [IsAuthenticated, OAuth2PermissionClass]
    queryset = Patient.objects.all()
    serializer_class = PatientSerializer

    def update(self, request, *args, **kwargs):
        try:
            patient = self.get_object()
        except ObjectDoesNotExist:
            return Response({'error': 'Patient not found'}, status=status.HTTP_404_NOT_FOUND)

        serializer = self.get_serializer(patient, data=request.data, partial=True)
        serializer.is_valid(raise_exception=True)

        try:
            patient.name = serializer.validated_data['name']
            patient.age = serializer.validated_data['age']
            patient.medical_conditions = serializer.validated_data['medical_conditions']
            patient.medications = serializer.validated_data['medications']

            patient.save()
            return Response(serializer.data, status=status.HTTP_200_OK)
        except IntegrityError as e:
            return Response({'error': 'Unique constraint failed'}, status=status.HTTP_400_BAD_REQUEST)
        except ValueError as e:
            return Response({'error': 'Invalid data'}, status=status.HTTP_400_BAD_REQUEST)

    def patch(self, request, *args, **kwargs):
        try:
            patient = self.get_object()
        except ObjectDoesNotExist:
            return Response({'error': 'Patient not found'}, status=status.HTTP_404_NOT_FOUND)

        serializer = self.get_serializer(patient, data=request.data, partial=True)
