        $articles = Article::with('languages')->get();

        return view('articles.index', compact('languages', 'articles'));
    }

    public function create()
    {
        $languages = Language::all();

        return view('articles.create', compact('languages'));
    }

    public function store(Request $request)
    {
        $article = Article::create($request->all());

        foreach ($request->input('languages') as $language) {
            LanguageArticle::create(['article_id' => $article->id, 'language_id' => $language]);
        }

        return redirect()->route('articles.index');
    }

    public function show(Article $article)
    {
        $languages = LanguageArticle::where('article_id', $article->id)->get();
        $languages = $languages->map(function ($language) {
            return [
                'id' => $language->id,
                'name' => $language->language->name,
                'text' => $language->text,
            ];
        });

        return view('articles.show', compact('article', 'languages'));
    }

    public function edit(Article $article)
    {
        $languages = Language::all();

        return view('articles.edit', compact('article', 'languages'));
    }

    public function update(Request $request, Article $article)
    {
        $article->update($request->all());

        foreach ($request->input('languages') as $language) {
            LanguageArticle::where('article_id', $article->id)->update(['language_id' => $language]);
        }

        return redirect()->route('articles.index');
    }

    public function destroy(Article $article)
    {
        LanguageArticle::where('article_id', $article->id)->delete();

        return redirect()->route('articles.index');
    }
