class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word.lower():
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word):
        node = self.root
        for char in word.lower():
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

    def starts_with(self, prefix):
        node = self.root
        for char in prefix.lower():
            if char not in node.children:
                return False
            node = node.children[char]
        return True

    def serialize(self):
        return self._serialize(self.root, "")

    def _serialize(self, node, prefix):
        if not node:
            return "##"
        if node.is_end_of_word:
            return f"{prefix}##"
        children = [self._serialize(child, prefix + char) for char, child in node.children.items()]
        return ",".join(children)

    def deserialize(self, data):
        nodes = data.split(",")
        self.root = self._deserialize(nodes, 0)
        return self.root

    def _deserialize(self, nodes, index):
        if nodes[index] == "##":
            node = TrieNode()
            node.is_end_of_word = True
            index += 1
        else:
            node = TrieNode()
            node.children = {}
            for char in nodes[index + 1:index + len(nodes[index]) - 2]:
                node.children[char] = self._deserialize(nodes, index + 1 + len(char))
            index += len(nodes[index]) - 2
        return node


class AutoCompleter:
    def __init__(self):
        self.trie = Trie()

    def insert(self, word):
        self.trie.insert(word)

    def search(self, word):
        return self.trie.search(word)

    def starts_with(self, prefix):
        return self.trie.starts_with(prefix)

    def serialize(self):
        return self.trie.serialize()

    def deserialize(self, data):
        self.trie = Trie()
        self.trie.deserialize(data)


# Example usage
auto_completer = AutoCompleter()

# Inserting words
auto_completer.insert("apple")
auto_completer.insert("banana")
auto_completer.insert("orange")

# Searching for words
print(auto_completer.search("apple"))  # True
print(auto_completer.search("app"))    # False

# Checking prefixes
print(auto_completer.starts_with("app"))  # True
print(auto_completer.starts_with("ban"))  # True

# Serializing and deserializing
serialized = auto_completer.serialize()
print(serialized)

deserialized = AutoCompleter()
deserialized.deserialize(serialized)
print(deserialized.search("apple"))  # True
