// UserController.java
@RestController
@RequestMapping("/users")
public class UserController {
    private final UserService userService;
    private final AuthenticationManager authenticationManager;

    @Autowired
    public UserController(UserService userService, AuthenticationManager authenticationManager) {
        this.userService = userService;
        this.authenticationManager = authenticationManager;
    }

    @PostMapping
    @PreAuthorize("hasRole('ADMIN')")
    public ResponseEntity<User> createUser(@RequestBody User user) {
        User existingUser = userRepository.findByUsername(user.getUsername()).orElse(null);
        if (existingUser != null) {
            return ResponseEntity.badRequest().build();
        }
        User createdUser = userService.createUser(user);
        return ResponseEntity.ok(createdUser);
    }
}

// PasswordEncoder.java
@Component
public class PasswordEncoder implements PasswordEncoder {
    @Override
    public boolean matches(String password, String salt) {
        // Simple implementation of BCrypt
        return BCrypt.checkpw(password, salt);
    }

    @Override
    public String encode(String password) {
        // Simple implementation of BCrypt
        return BCrypt.hashpw(password, BCrypt.gensalt());
    }
}

// UserConfig.java
@Configuration
@EnableWebSecurity
public class UserConfig extends WebSecurityConfigurerAdapter {
    @Autowired
    private PasswordEncoder passwordEncoder;

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http.authorizeRequests()
                .antMatchers("/actuator/health", "/actuator/prometheus").permitAll()
                .anyRequest().authenticated()
                .and()
                .oauth2Login()
                .userDetailsService(userService())
                .and()
                .oauth2AuthorizationServer()
                .tokenEndpoint().sessionCreationPolicy(SessionCreationPolicy.STATELESS)
                .and()
                .oauth2ClientAuthenticationManager(authenticationManager());
    }

    @Override
    protected void configure(AuthenticationManagerBuilder auth) throws Exception {
        auth.userDetailsService(userService()).passwordEncoder(passwordEncoder);
    }

    @Bean
    public UserDetailsService userService() {
        return new UserDetailsService() {
            @Override
            public UserDetails loadUserByUsername(String username) throws UsernameNotFoundException {
                User user = userRepository.findByUsername(username).orElseThrow();
                return new org.springframework.security.core.userdetails.User(user.getUsername(), user.getPassword(), getAuthorities(user.getRoles()));
            }

            private List<GrantedAuthority> getAuthorities(Set<String> roles) {
                List<GrantedAuthority> authorities = new ArrayList<>();
                roles.forEach(role -> authorities.add(new SimpleGrantedAuthority(role)));
                return authorities;
            }
        };
    }
}

