devices = {
    'fitbit': {'url': 'https://api.fitbit.com/1/user/-/activities.json', 'key': 'fitbit_api_key'},
    'garmin': {'url': 'https://api.garmin.com/v3/user/-/activities.json', 'key': 'garmin_api_key'}
}

# Function to fetch data from a device API
def fetch_device_data(device_type, date_range):
    url = devices[device_type]['url']
    params = {
        'date': date_range['start'],
        'end': date_range['end'],
        'limit': 100
    }
    headers = {
        'Authorization': f'Bearer {devices[device_type]["key"]}'
    }
    response = requests.get(url, params=params, headers=headers)
    response.raise_for_status()
    return response.json()

# Function to aggregate data from multiple device APIs
def aggregate_device_data(device_types, date_range):
    aggregated_data = {}
    for device_type in device_types:
        data = fetch_device_data(device_type, date_range)
        aggregated_data[device_type] = data
    return aggregated_data

# API endpoint to fetch and aggregate device data
@app.route('/api/devices/data', methods=['GET'])
@cache.cached(query_string=True)
def get_device_data():
    device_types = request.args.getlist('device')
    date_range = request.args.get('date_range')
    if not device_types or not date_range:
        return jsonify({'error': 'Invalid request parameters'}), 400
    if not all(device_type in devices for device_type in device_types):
        return jsonify({'error': 'Invalid device type'}), 400
    if not isinstance(date_range, dict) or 'start' not in date_range or 'end' not in date_range:
        return jsonify({'error': 'Invalid date range'}), 400
    aggregated_data = aggregate_device_data(device_types, date_range)
    return jsonify(aggregated_data)

if __name__ == '__main__':
