namespace CMS\Plugins\UploadValidation;

use CMS\Core\Plugin;
use CMS\Core\PluginManager;
use CMS\Core\HookInterface;
use CMS\Core\HookManager;
use CMS\Core\HookEvent;
use CMS\Core\Error;
use ClamAV\ClamAV;

class UploadValidationPlugin extends Plugin implements HookInterface
{
    const PLUGIN_NAME = 'Upload Validation';
    const PLUGIN_DESCRIPTION = 'Restricts uploads based on file type and size, and scans uploaded documents for malware using ClamAV.';
    const PLUGIN_VERSION = '1.0';

    private $clamav;

    public function __construct()
    {
        $this->clamav = new ClamAV();
    }

    public function getName()
    {
        return self::PLUGIN_NAME;
    }

    public function getDescription()
    {
        return self::PLUGIN_DESCRIPTION;
    }

    public function getVersion()
    {
        return self::PLUGIN_VERSION;
    }

    public function getHooks()
    {
        return [
            HookEvent::FILE_UPLOADED => $this->onFileUploaded,
            HookEvent::UPLOAD_DENIED => $this->onUploadDenied,
        ];
    }

    public function onFileUploaded($event)
    {
        $file = $event['file'];
        $fileSize = $event['fileSize'];
        $allowedExtensions = ['pdf', 'docx', 'txt', 'jpg', 'png'];

        if (!in_array($file->getClientOriginalExtension(), $allowedExtensions)) {
            $event['denied'] = true;
            $event['deniedMessage'] = 'File type not allowed.';
            return;
        }

        if ($fileSize > 1024 * 1024 * 5) {
            $event['denied'] = true;
            $event['deniedMessage'] = 'File size exceeds the maximum allowed size (5MB).';
            return;
        }

        try {
            $scannedFile = $this->clamav->scan($file);
            if ($scannedFile->getSeverity() !== 0) {
                $event['denied'] = true;
                $event['deniedMessage'] = 'File detected as malicious.';
                return;
            }
        } catch (\Exception $e) {
            $event['denied'] = true;
            $event['deniedMessage'] = 'Error scanning file for malware: ' . $e->getMessage();
            return;
        }

        // File is valid, proceed with upload
    }

    public function onUploadDenied($event)
    {
        $error = new Error();
        $error->setCode('upload_denied');
        $error->setMessage($event['deniedMessage']);
        return $error;
    }
}

class UploadValidationPluginManager extends PluginManager
{
    public function register()
    {
        $this->registerPlugin(new UploadValidationPlugin());
    }
}
