const Koa = require('koa');
const KoaRouter = require('koa-router');
const KoaLogger = require('koa-logger');
const KoaRateLimit = require('koa-rate-limit');
const crypto = require('crypto');
const axios = require('axios');

class WebhookService {
  constructor(app) {
    this.app = app;
    this.webhookRouter = new KoaRouter();
    this.webhookStore = [];
    this.logger = new KoaLogger();
    this.rateLimiter = new KoaRateLimit({
      keyGen: (ctx) => ctx.request.ip,
      max: 10,
      windowMs: 60 * 1000,
    });
  }

  async registerWebhook(ctx) {
    const { event, url, secret } = ctx.request.body;
    if (!event || !url || !secret) {
      ctx.status = 400;
      ctx.body = { error: 'Invalid request body' };
      return;
    }

    const hmac = crypto.createHmac('sha256', secret);
    hmac.update(`${event}${Date.now()}`);
    const signature = hmac.digest('hex');
    if (signature !== ctx.request.header['x-hmac'] || signature !== ctx.request.header['x-hmac'] || signature !== ctx.request.header['x-hmac']) {
      ctx.status = 401;
      ctx.body = { error: 'Invalid HMAC signature' };
      return;
    }

    this.webhookStore.push({ event, url });
    ctx.body = { message: 'Webhook registered successfully' };
  }

  async updateWebhook(ctx) {
    const { id, event, url, secret } = ctx.request.body;
    if (!id || !event || !url || !secret) {
      ctx.status = 400;
      ctx.body = { error: 'Invalid request body' };
      return;
    }

    const webhook = this.webhookStore.find((webhook) => webhook.id === id);
    if (!webhook) {
      ctx.status = 404;
      ctx.body = { error: 'Webhook not found' };
      return;
    }

    const hmac = crypto.createHmac('sha256', secret);
    hmac.update(`${event}${Date.now()}`);
    const signature = hmac.digest('hex');
    if (signature !== ctx.request.header['x-hmac']) {
      ctx.status = 401;
      ctx.body = { error: 'Invalid HMAC signature' };
      return;
    }

    webhook.event = event;
    webhook.url = url;
    ctx.body = { message: 'Webhook updated successfully' };
  }

  async deleteWebhook(ctx) {
    const { id } = ctx.request.body;
    if (!id) {
      ctx.status = 400;
      ctx.body = { error: 'Invalid request body' };
      return;
    }

    const webhook = this.webhookStore.find((webhook) => webhook.id === id);
    if (!webhook) {
      ctx.status = 404;
      ctx.body = { error: 'Webhook not found' };
      return;
    }

    this.webhookStore.splice(this.webhookStore.indexOf(webhook), 1);
    ctx.body = { message: 'Webhook deleted successfully' };
  }

  async dispatchWebhook(ctx) {
    const webhook = this.webhookStore.find((webhook) => webhook.event === ctx.request.body.event);
    if (!webhook) {
      ctx.status = 404;
      ctx.body = { error: 'Webhook not found' };
      return;
    }

    const hmac = crypto.createHmac('sha256', webhook.secret);
    hmac.update(`${webhook.event}${Date.now()}`);
    const signature = hmac.digest('hex');
    if (signature !== ctx.request.header['x-hmac']) {
      ctx.status = 401;
      ctx.body = { error: 'Invalid HMAC signature' };
      return;
    }

    try {
      await axios.post(webhook.url, { event: webhook.event });
      ctx.body = { message: 'Webhook dispatched successfully' };
    } catch (error) {
      ctx.status = 500;
      ctx.body = { error: 'Failed to dispatch webhook' };
    }
  }

  async POST(ctx) {
    this.rateLimiter(ctx);
    await this.webhookRouter(ctx);
  }

  async GET(ctx) {
    ctx.body = this.webhookStore;
  }
}

async function main() {
  const app = new Koa();
  const webhookService = new WebhookService(app);
  webhookService.webhookRouter.post('/webhooks', webhookService.registerWebhook);
  webhookService.webhookRouter.put('/webhooks/:id', webhookService.updateWebhook);
  webhookService.webhookRouter.delete('/webhooks/:id', webhookService.deleteWebhook);
  webhookService.webhookRouter.post('/webhooks/:id/dispatch', webhookService.dispatchWebhook);
  app.use(webhookService.webhookRouter.routes()).use(webhookService.webhookRouter.allowedMethods());
  app.use(webhookService.logger);
  app.listen(3000, () => {
    console.log('Webhook service listening on port 3000');
  });
}

main();
