# payment_processors.py

import stripe
from stripe.error import StripeError
from abc import ABC, abstractmethod
from enum import Enum
from typing import Dict

class PaymentGatewayEnum(str, Enum):
    STRIPE = "stripe"

class PaymentProcessor(ABC):
    @abstractmethod
    def process_payment(self, amount: float, currency: str, payment_method: Dict) -> bool:
        pass

class StripePaymentProcessor(PaymentProcessor):
    def __init__(self):
        stripe.api_key = "YOUR_STRIPE_SECRET_KEY"

    def process_payment(self, amount: float, currency: str, payment_method: Dict) -> bool:
        try:
            # Create a Stripe customer
            customer = stripe.Customer.create(
                email=payment_method.get("email"),
                name=payment_method.get("name"),
                address=payment_method.get("address")
            )

            # Create a Stripe payment intent
            payment_intent = stripe.PaymentIntent.create(
                amount=int(amount * 100),
                currency=currency,
                payment_method_types=[PaymentGatewayEnum.STRIPE.value],
                setup_future_usage="off_session"
            )

            # Confirm the payment intent
            payment_intent.confirm()

            return True

        except StripeError as e:
            if e.code == "invalid_request":
                raise ValueError("Invalid payment method or amount") from e
            elif e.code == "insufficient_funds":
                raise ValueError("Insufficient funds") from e
            elif e.code == "unauthorized":
                raise ValueError("Unauthorized") from e
            elif e.code == "invalid_request_parameters":
                raise ValueError("Invalid payment method or amount") from e
            else:
                raise ValueError("An error occurred while processing the payment") from e

