import React, { useState, useEffect } from 'react';
import { createStore, combineReducers, applyMiddleware } from 'redux';
import { Provider, useSelector, useDispatch } from 'react-redux';
import thunk from 'redux-thunk';
import { FilterActions } from './actions';
import { ProductList } from './components/ProductList';
import { Filter } from './components/Filter';

const initialState = {
  products: [
    { id: 1, name: 'Product 1', category: 'Electronics' },
    { id: 2, name: 'Product 2', category: 'Clothing' },
    { id: 3, name: 'Product 3', category: 'Books' },
  ],
  filters: {
    category: 'Electronics',
  },
};

const reducer = combineReducers({
  products: (state = initialState.products, action) => {
    switch (action.type) {
      case FilterActions.SET_FILTERS:
        return { ...state, filters: action.payload };
      default:
        return state;
    }
  },
});

const store = createStore(reducer, applyMiddleware(thunk));

const FilterComponent = () => {
  const dispatch = useDispatch();
  const [category, setCategory] = useState(initialState.filters.category);

  useEffect(() => {
    dispatch({ type: FilterActions.SET_FILTERS, payload: { category } });
  }, [category]);

  const handleCategoryChange = (newCategory) => {
    setCategory(newCategory);
  };

  return (
    <div>
      <Filter
        categories={['Electronics', 'Clothing', 'Books']}
        selectedCategory={category}
        onCategoryChange={handleCategoryChange}
      />
      <ProductList products={useSelector((state) => state.products)} />
    </div>
  );
};

const App = () => {
  return (
    <Provider store={store}>
      <FilterComponent />
    </Provider>
  );
};

export default App;
