import { PaymentResponseDto } from './dtos/payment-response.dto';

@Injectable()
export class PaymentController {
  constructor(
    @InjectModel('Payment')
    private readonly paymentModel: Model<PaymentDocument>,
    private readonly paymentService: PaymentService,
  ) {}

  @Post('/payments')
  @ApiOperation({ summary: 'Create a new payment' })
  @ApiResponses([
    {
      status: HttpStatus.CREATED,
      description: 'Payment created successfully',
      content: {
        'application/json': {
          schema: {
            type: 'object',
            properties: {
              paymentId: { type: 'string' },
              clientSecret: { type: 'string' },
            },
          },
        },
      },
    },
    {
      status: HttpStatus.BAD_REQUEST,
      description: 'Validation error',
      content: {
        'application/json': {
          schema: {
            type: 'object',
            properties: {
              errors: { type: 'array', items: { type: 'object' } },
            },
          },
        },
      },
    },
    {
      status: HttpStatus.INTERNAL_SERVER_ERROR,
      description: 'Payment gateway error',
      content: {
        'application/json': {
          schema: {
            type: 'object',
            properties: {
              error: { type: 'string' },
              details: { type: 'object' },
            },
          },
        },
      },
    },
  ])
  async createPayment(
    @Body(new ValidatePaymentDto()) createPaymentDto: CreatePaymentDto,
    @Req() req: any,
  ): Promise<PaymentResponseDto> {
    if (!req.headers['x-api-key']) {
      throw new HttpException('Missing API key', HttpStatus.UNAUTHORIZED);
    }

    try {
      const payment = await this.paymentService.createPayment(
        createPaymentDto,
        req.headers['x-api-key'],
      );

      const stripe = stripe(process.env.STRIPE_SECRET_KEY);
      const paymentIntent = await stripe.paymentIntents.create({
        amount: createPaymentDto.amount,
        currency: createPaymentDto.currency,
      });

      await this.paymentModel.findByIdAndUpdate(
        payment._id,
        {
          $set: {
            stripePaymentIntentId: paymentIntent.id,
            clientSecret: paymentIntent.client_secret,
          },
        },
        { new: true },
        { session: true },
      );

      return { paymentId: payment._id.toString(), clientSecret: paymentIntent.client_secret };
    } catch (error) {
      if (error instanceof StripeError) {
        await this.paymentModel.abortSession(error.stripeError);
        throw new HttpException('Payment gateway error', HttpStatus.INTERNAL_SERVER_ERROR);
      } else {
        throw error;
      }
    }
  }
}

