import sqlite3
from sqlite3 import Error

class Book:
    def __init__(self, isbn, title, author, availability=True):
        self.isbn = isbn
        self.title = title
        self.author = author
        self.availability = availability

    def __str__(self):
        return f"ISBN: {self.isbn}, Title: {self.title}, Author: {self.author}, Availability: {self.availability}"


class Member:
    def __init__(self, member_id, name):
        self.member_id = member_id
        self.name = name
        self.borrowed_books = []

    def __str__(self):
        return f"Member ID: {self.member_id}, Name: {self.name}, Borrowed Books: {self.borrowed_books}"


class Library:
    def __init__(self, db_name):
        self.conn = None
        self.cursor = None
        self.create_connection(db_name)

    def create_connection(self, db_name):
        try:
            self.conn = sqlite3.connect(db_name)
            self.cursor = self.conn.cursor()
            self.cursor.execute("""
                CREATE TABLE IF NOT EXISTS books (
                    isbn TEXT PRIMARY KEY,
                    title TEXT,
                    author TEXT,
                    availability TEXT DEFAULT TRUE
                )
            """)
            self.cursor.execute("""
                CREATE TABLE IF NOT EXISTS members (
                    member_id TEXT PRIMARY KEY,
                    name TEXT,
                    borrowed_books TEXT
                )
            """)
        except Error as e:
            print(e)

    def add_book(self, isbn, title, author):
        self.cursor.execute("INSERT INTO books VALUES (?, ?, ?, ?)", (isbn, title, author, "TRUE"))
        self.conn.commit()

    def register_member(self, member_id, name):
        self.cursor.execute("INSERT INTO members VALUES (?, ?, ?)", (member_id, name, ""))
        self.conn.commit()

    def borrow_book(self, member_id, book_isbn):
        self.cursor.execute("SELECT * FROM members WHERE member_id = ?", (member_id,))
        member = self.cursor.fetchone()
        if member:
            self.cursor.execute("SELECT * FROM books WHERE isbn = ?", (book_isbn,))
            book = self.cursor.fetchone()
            if book and book[4] == "TRUE":
                self.cursor.execute("UPDATE books SET availability = FALSE WHERE isbn = ?", (book_isbn,))
                self.cursor.execute("UPDATE members SET borrowed_books = ? WHERE member_id = ?", (book_isbn + "," + member[2], member[0]))
                self.conn.commit()
                return True
        return False

    def return_book(self, member_id, book_isbn):
        self.cursor.execute("SELECT * FROM members WHERE member_id = ?", (member_id,))
        member = self.cursor.fetchone()
        if member:
            self.cursor.execute("SELECT * FROM books WHERE isbn = ?", (book_isbn,))
            book = self.cursor.fetchone()
            if book and book[4] == "FALSE":
                self.cursor.execute("UPDATE books SET availability = TRUE WHERE isbn = ?", (book_isbn,))
                self.cursor.execute("UPDATE members SET borrowed_books = ? WHERE member_id = ?", (book_isbn, member[2]))
                self.conn.commit()
                return True
        return False

    def close_connection(self):
        if self.conn:
            self.conn.close()


def main():
    library = Library("library.db")

    while True:
        print("Library Management System")
        print("1. Add Book")
        print("2. Register Member")
        print("3. Borrow Book")
        print("4. Return Book")
        print("5. Exit")

        choice = input("Enter your choice: ")

        if choice == "1":
            isbn = input("Enter ISBN: ")
            title = input("Enter Title: ")
            author = input("Enter Author: ")
            library.add_book(isbn, title, author)
        elif choice == "2":
            member_id = input("Enter Member ID: ")
            name = input("Enter Name: ")
            library.register_member(member_id, name)
        elif choice == "3":
            member_id = input("Enter Member ID: ")
            book_isbn = input("Enter ISBN of Book to Borrow: ")
            if library.borrow_book(member_id, book_isbn):
                print("Book borrowed successfully.")
            else:
                print("Book not available or member not found.")
        elif choice == "4":
            member_id = input("Enter Member ID: ")
            book_isbn = input("Enter ISBN of Book to Return: ")
            if library.return_book(member_id, book_isbn):
                print("Book returned successfully.")
            else:
                print("Book not found or already returned.")
        elif choice == "5":
            library.close_connection()
            break
        else:
            print("Invalid choice. Please try again.")

if __name__ == "__main__":
    main()
