        <label for="price-max">Max</label>
      </div>
    </div>

    <button @click="applyFilters">Apply Filters</button>
  </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex';

export default {
  computed: {
    ...mapGetters(['products', 'selectedFilters'])
  },
  methods: {
    ...mapActions(['setSelectedFilters', 'getProducts'])
  },
  mounted() {
    this.getProducts();
  },
  watch: {
    selectedFilters: {
      handler() {
        this.applyFilters();
      },
      deep: true
    }
  },
  methods: {
    applyFilters() {
      const { priceMin, priceMax, ...brandFilters } = this.selectedFilters;
      const filteredProducts = this.products.filter(product => {
        let brandMatch = false;
        for (const brand in brandFilters) {
          if (brandFilters[brand] && product.brand === brand) {
            brandMatch = true;
            break;
          }
        }
        if (!brandMatch) return false;

        let ratingMatch = false;
        for (const rating in brandFilters) {
          if (brandFilters[rating] && product.rating === rating) {
            ratingMatch = true;
            break;
          }
        }
        if (!ratingMatch) return false;

        if (priceMin < product.price && product.price < priceMax) return true;
        return false;
      });
      this.setSelectedFilters({ priceMin, priceMax });
      this.$emit('update:products', filteredProducts);
    }
  }
}
</script>

// store.js
import Vue from 'vue';
import Vuex from 'vuex';

Vue.use(Vuex);

const store = new Vuex.Store({
  state: {
    products: [],
    selectedFilters: {
      priceMin: 0,
      priceMax: 1000
    }
  },
  mutations: {
    setSelectedFilters(state, filters) {
      state.selectedFilters = filters;
    },
    getProducts(state, products) {
      state.products = products;
    }
  },
  actions: {
    setSelectedFilters({ commit, rootGetters }, filters) {
      commit('setSelectedFilters', filters);
      return rootGetters.products;
    },
    getProducts({ commit }, products) {
      commit('getProducts', products);
    }
  }
});

export default store;
