from datetime import datetime
from pymongo import MongoClient
from bson import ObjectId
import uuid
import json

class ClassScheduler:
    def __init__(self, mongo_url, mongo_db):
        self.mongo_url = mongo_url
        self.mongo_db = mongo_db
        self.client = MongoClient(self.mongo_url)
        self.db = self.client[self.mongo_db]
        self.classes_collection = self.db['classes']

    def validate_class(self, title, description, start_time, duration_minutes):
        if not title:
            raise ValueError('Title is required')
        if description and not description.strip():
            raise ValueError('Description cannot be empty')
        try:
            datetime.strptime(start_time, '%Y-%m-%dT%H:%M:%S.%fZ')
        except ValueError:
            raise ValueError('Invalid start time format')
        if duration_minutes <= 0:
            raise ValueError('Duration must be greater than 0 minutes')

    def schedule_class(self, title, description=None, start_time=None, duration_minutes=None):
        try:
            self.validate_class(title, description, start_time, duration_minutes)
        except ValueError as e:
            print(f'Invalid class data: {e}')
            return None

        class_data = {
            'title': title,
            'description': description,
            'start_time': start_time,
            'duration_minutes': duration_minutes,
            'id': str(uuid.uuid4())
        }

        self.classes_collection.insert_one(class_data)
        return class_data

    def get_classes(self):
        return list(self.classes_collection.find())

    def get_class(self, class_id):
        return self.classes_collection.find_one({'id': ObjectId(class_id)})

def main():
    mongo_url = 'mongodb://localhost:27017'
    mongo_db = 'educational_system'
    scheduler = ClassScheduler(mongo_url, mongo_db)

    title = 'Math Class'
    description = 'Math class for students'
    start_time = '2023-03-01T14:00:00.000Z'
    duration_minutes = 60

    class_data = scheduler.schedule_class(title, description, start_time, duration_minutes)
    print(json.dumps(class_data, indent=4))

    classes = scheduler.get_classes()
    for class_data in classes:
        print(json.dumps(class_data, indent=4))

    class_data = scheduler.get_class(class_data['_id'])
    print(json.dumps(class_data, indent=4))

if __name__ == '__main__':
    main()
