import json
import os

# Constants
ROOMS = {
    'hallway': {
        'description': 'You are in a grand hallway.',
        'items': ['key'],
        'actions': ['go north', 'take key', 'go back'],
        'next_room': 'kitchen'
    },
    'kitchen': {
        'description': 'You are in a kitchen.',
        'items': ['knife'],
        'actions': ['go back', 'take knife', 'use knife'],
        'next_room': 'hallway'
    }
}

# Player class
class Player:
    def __init__(self, room, inventory, progress):
        self.room = room
        self.inventory = inventory
        self.progress = progress

    def move(self, direction):
        if direction in ROOMS[self.room]['actions']:
            if direction == 'go back' and self.room != ROOMS['hallway']['next_room']:
                self.room = ROOMS['hallway']['next_room']
            elif direction in ROOMS[self.room]['actions']:
                self.room = ROOMS[self.room]['next_room']
            else:
                print("You cannot go that way.")
        else:
            print("Invalid action.")

    def take_item(self, item):
        if item in ROOMS[self.room]['items']:
            self.inventory.append(item)
            ROOMS[self.room]['items'].remove(item)
            print(f"You took {item}.")
        else:
            print("That item is not here.")

    def use_item(self, item):
        if item in self.inventory:
            if item == 'knife':
                print("You used the knife to cut the rope.")
            else:
                print("You do not have that item.")
        else:
            print("You do not have that item.")

    def save_progress(self):
        with open('progress.json', 'w') as f:
            json.dump({
                'room': self.room,
                'inventory': self.inventory,
                'progress': self.progress
            }, f)

    def load_progress(self):
        if os.path.exists('progress.json'):
            with open('progress.json', 'r') as f:
                data = json.load(f)
                self.room = data['room']
                self.inventory = data['inventory']
                self.progress = data['progress']
                print("Progress loaded.")
        else:
            print("No saved progress found.")

def main():
    player = Player('hallway', [], 0)
    while True:
        print("\n" + ROOMS[player.room]['description'])
        print("Items: " + ", ".join(player.inventory))
        print("Actions: " + ", ".join(ROOMS[player.room]['actions']))
        action = input("What do you want to do? ").lower()
        if action in ['go north', 'go back']:
            player.move(action)
        elif action in ['take key']:
            player.take_item('key')
        elif action in ['take knife']:
            player.take_item('knife')
        elif action in ['use knife']:
            player.use_item('knife')
        elif action == 'save':
            player.save_progress()
        elif action == 'load':
            player.load_progress()
        else:
            print("Invalid action.")

if __name__ == "__main__":
    main()
