const express = require('express');
const app = express();
const rateLimit = require('express-rate-limit');
const log4js = require('log4js');
const adminInterface = require('./adminInterface');

// Set up logging
log4js.configure({
  appenders: { console: { type: 'console' } },
  categories: { default: { appenders: ['console'], level: 'debug' } }
});
const logger = log4js.getLogger();

// Set up IP blocking list
const blockedIps = new Set();

// Set up rate limiting middleware
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // 100 requests per 15 minutes
});

// Apply rate limiting middleware to all routes
app.use(limiter);

// Define a middleware function to block IPs exceeding the threshold
function blockIp(ip) {
  if (blockedIps.has(ip)) {
    return;
  }
  blockedIps.add(ip);
  logger.info(`Blocked IP: ${ip}`);
  // Add IP to admin interface
  adminInterface.addBlockedIp(ip);
}

// Define a middleware function to allow IP if not blocked
function allowIp(ip) {
  if (blockedIps.has(ip)) {
    blockedIps.delete(ip);
    logger.info(`Unblocked IP: ${ip}`);
    // Remove IP from admin interface
    adminInterface.removeBlockedIp(ip);
  }
}

// Apply allow IP middleware to all routes
app.use((req, res, next) => {
  const ip = req.ip;
  blockIp(ip);
  next();
});

// Define a route to review and manage blocked IPs
app.get('/admin/blockedList', (req, res) => {
  const blockedIpsList = Array.from(blockedIps);
  res.json(blockedIpsList);
});

// Add admin interface route to express server
app.use('/admin', adminInterface);

// Start the server
const port = 3000;
app.listen(port, () => {
  console.log(`Server started on port ${port}`);
});
