using System;
using System.Net.Http;
using System.Net.Http.Headers;
using System.Text.Json;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Caching.Memory;
using Moq;
using Polly;
using Polly.CircuitBreaker;
using Polly.Extensions.Http;
using Polly.Retry;
using Polly.Retry.PolicyBuilder;
using Polly.Timeout;
using Swashbuckle.AspNetCore.SwaggerGen;
using Xunit;
using Xunit.Extensions.Xunit;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Http;

public class CurrencyConverterController : Controller
{
    private readonly ILogger<CurrencyConverterController> _logger;
    private readonly IMemoryCache _memoryCache;
    private readonly HttpClient _httpClient;

    public CurrencyConverterController(ILogger<CurrencyConverterController> logger, IMemoryCache memoryCache, HttpClient httpClient)
    {
        _logger = logger;
        _memoryCache = memoryCache;
        _httpClient = httpClient;
    }

    [HttpGet]
    [Route("convert")]
    public async Task<IActionResult> ConvertCurrency([FromQuery] string fromCurrency, [FromQuery] string toCurrency, [FromQuery] decimal amount)
    {
        if (string.IsNullOrEmpty(fromCurrency) || string.IsNullOrEmpty(toCurrency) || amount <= 0)
        {
            return BadRequest(new { error = "Invalid input", details = "Please provide valid fromCurrency, toCurrency, and amount" });
        }

        var cacheKey = $"{fromCurrency}-{toCurrency}";
        var cachedRate = _memoryCache.Get<string>(cacheKey);

        if (!string.IsNullOrEmpty(cachedRate))
        {
            var rate = JsonSerializer.Deserialize<decimal>(cachedRate);
            return Ok(new
            {
                fromCurrency,
                toCurrency,
                exchangeRate = rate,
                originalAmount = amount,
                convertedAmount = amount * rate,
                timestamp = DateTime.UtcNow
            });
        }

        var policy = Policy.Handle<HttpRequestException>()
            .WaitAndRetryAsync(
                retryCount: 3,
                retryDelay: Policy.Handle<HttpRequestException>().WaitAndRetryAsync(exponentialBackoff: true));

        policy = policy.TimeoutAsync(TimeSpan.FromMinutes(5));

        policy = policy.CircuitBreakerAsync(
            circuitBreaker: new CircuitBreakerPolicy<HttpRequestException>(5, TimeSpan.FromSeconds(30)));

        var response = await policy.ExecuteAsync(async () =>
        {
            var request = new HttpRequestMessage(HttpMethod.Get, $"https://exchangeratesapi.io/api/latest?base={fromCurrency}&symbols={toCurrency}");
            request.Headers.Authorization = new AuthenticationHeaderValue("Bearer", "YOUR_API_KEY");

            var result = await _httpClient.SendAsync(request);
            result.EnsureSuccessStatusCode();

            var rate = JsonSerializer.Deserialize<RateResponse>(await result.Content.ReadAsStringAsync());
            _memoryCache.Set(cacheKey, rate.exchangeRate.ToString(), TimeSpan.FromMinutes(5));

            return rate;
        });

        if (response.IsSuccessStatusCode)
        {
            var rate = JsonSerializer.Deserialize<RateResponse>(await response.Content.ReadAsStringAsync());
            return Ok(new
            {
                fromCurrency,
                toCurrency,
                exchangeRate = rate.exchangeRate,
                originalAmount = amount,
                convertedAmount = amount * rate.exchangeRate,
                timestamp = DateTime.UtcNow
            });
        }
        else if (response.StatusCode == System.Net.HttpStatusCode.ServiceUnavailable)
        {
            return StatusCode(503, new { error = "Rate service unavailable", details = "Please try again later" });
        }
        else
        {
            return StatusCode((int)response.StatusCode, new { error = "Rate service unavailable", details = "Please try again later" });
        }
    }

