def subscribe(request):
    if request.method == 'POST':
        form = SubscribeForm(request.POST)
        if form.is_valid():
            user = User.objects.create(email=form.cleaned_data['email'])
            subscription = Subscription.objects.create(user_id=user.user_id, subscription_status=True)
            messages.success(request, 'You have successfully subscribed.')
            return redirect('subscription')
    else:
        form = SubscribeForm()
    return render(request, 'subscribe.html', {'form': form})

def unsubscribe(request):
    if request.method == 'POST':
        form = UnsubscribeForm(request.POST)
        if form.is_valid():
            user = User.objects.get(email=form.cleaned_data['email'])
            subscription = Subscription.objects.filter(user_id=user.user_id).first()
            subscription.subscription_status = False
            subscription.save()
            messages.success(request, 'You have successfully unsubscribed.')
