import csv

class Task:
    def __init__(self, name, priority, duration):
        self.name = name
        self.priority = priority
        self.duration = duration

def load_tasks(filename):
    tasks = []
    with open(filename, 'r') as file:
        reader = csv.DictReader(file)
        for row in reader:
            tasks.append(Task(row['name'], int(row['priority']), int(row['duration'])))
    return tasks

def schedule_tasks(tasks):
    tasks.sort(key=lambda task: (task.priority, task.duration))
    return tasks

def print_schedule(tasks):
    for task in tasks:
        print(f"Task: {task.name}, Priority: {task.priority}, Duration: {task.duration} minutes")

def main():
    filename = 'tasks.csv'  # replace with your CSV file
    tasks = load_tasks(filename)
    scheduled_tasks = schedule_tasks(tasks)
    print_schedule(scheduled_tasks)

if __name__ == "__main__":
    main()
